insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:3-3-communication-in-business:exam:e5023e26', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'exam', 'mcq', 1, '{"num": "Q5 (a)", "question": "Explain the term ''digital communications''. [1 mark]", "options": ["Sending letters and leaflets to customers", "The electronic exchange of information using ICT", "Face-to-face communication between people", "The use of meetings and presentations in business"], "caseStudy": "Amazon is one the best examples of a business that benefited from the revolution in digital communication. It started as a book seller in the 1990s. By selling books online, it did not need shops on the high street. Books were stored in warehouses and delivered directly to customers at reduced prices. Amazon sold to customers all over the USA then expanded globally. It uses robots in some of its warehouses — once received, the order is communicated directly to a robot which retrieves the product.", "hint": "Think about what makes communication ''digital'' — what technology is involved?", "starter": "Digital communication is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — The electronic exchange of information using ICT</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>Digital communication is specifically the electronic exchange of information using ICT. This includes email, websites, faxes, social media, and programming machines/robots to respond to data. Letters and face-to-face communication are non-digital.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-3-communication-in-business:mcq:2a75cf14', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "Which of these statements is FALSE?", "options": ["Digital communication involves the electronic transfer of information", "Mobile phones, computers and tablets can transfer information electronically", "Digital communication is always better than non-digital communication", "Digital communication has been a major force behind the globalisation of business"]}'::jsonb, '{"answer": 2, "explain": "Digital communication is NOT always better than non-digital. Face-to-face meetings, for example, allow immediate feedback, body language, and discussion that digital communication cannot always replicate. ''Always'' is a giveaway that this statement is false."}'::jsonb),
('business:3-3-communication-in-business:mcq:fc7f3a36', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT an advantage of meetings?", "options": ["There will usually be a record of formal meetings in the form of minutes", "The sender of the message can always be seen and heard by the receiver", "The sender can check immediately whether the receiver has understood the message", "It is a way of avoiding confrontation when the message is given"]}'::jsonb, '{"answer": 3, "explain": "Avoiding confrontation is an advantage of WRITTEN communication, not meetings. Meetings involve face-to-face interaction, which can actually make confrontation more likely. Written communication allows a message to be delivered without direct conflict."}'::jsonb),
('business:3-3-communication-in-business:mcq:05db713a', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT true about digital communication?", "options": ["It has helped to increase globalisation of business", "The development of digital communication has benefited all workers", "It has increased competition often leading to lower prices", "It has made it possible for some workers to work at home"]}'::jsonb, '{"answer": 1, "explain": "Digital communication has NOT benefited ALL workers. While many have gained new opportunities and flexibility, others have lost their jobs as productivity improved and automation replaced roles. Workers have also had to undergo retraining."}'::jsonb),
('business:3-3-communication-in-business:mcq:19b60a8d', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "In 2021, Instagram had 1 billion users. 300 million were aged 18–24. The percentage of Instagram users in the 18–24 bracket is:", "options": ["3%", "13%", "30%", "33%"]}'::jsonb, '{"answer": 2, "explain": "300 million ÷ 1,000 million × 100 = 30%. This shows how Instagram is heavily used by young people, making it a strong platform for businesses targeting under-35 customers."}'::jsonb),
('business:3-3-communication-in-business:mcq:c3e20403', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "What is a disadvantage for a business of using digital communication?", "options": ["It is a slow method of communication", "Pictures and videos cannot be shared", "The technology on which it relies can fail", "Worldwide communication is not possible"]}'::jsonb, '{"answer": 2, "explain": "Technology failure is a real risk of digital communication — systems can crash, lose data, or be disrupted by cyber-attacks or power cuts. Options A, B, and D are all incorrect: digital communication is fast, can share rich media, and enables worldwide reach."}'::jsonb),
('business:3-3-communication-in-business:mcq:cc15be9b', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "A market research agency spent £250,000 on digital communication in 2017 and £525,000 in 2018. The percentage increase was approximately:", "options": ["48%", "52%", "110%", "210%"]}'::jsonb, '{"answer": 2, "explain": "Percentage change = (New − Old) ÷ Old × 100 = (525,000 − 250,000) ÷ 250,000 × 100 = 275,000 ÷ 250,000 × 100 = 110%. A common mistake is dividing by the NEW value — always divide by the ORIGINAL value."}'::jsonb),
('business:3-3-communication-in-business:mcq:6cdb9f65', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "Which of these is an example of digital communication?", "options": ["A face-to-face interview", "A letter", "A magazine", "A website"]}'::jsonb, '{"answer": 3, "explain": "A website is digital communication — it uses ICT to exchange information electronically. A face-to-face interview is verbal, a letter is written (non-digital), and a magazine is print media."}'::jsonb),
('business:3-3-communication-in-business:mcq:8cafd0d2', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "A frozen food manufacturer urgently needs its maintenance contractor to repair its freezers. Which is the best method?", "options": ["Post a message on its website saying it has problems with freezers", "Produce a presentation to explain the problem", "Send a letter by first class post", "Telephone the maintenance contractor and explain the problem"]}'::jsonb, '{"answer": 3, "explain": "The phone is the best method here because it is URGENT and requires TWO-WAY communication so the contractor can ask questions and clarify details immediately. A letter is too slow, a website post is not directed at the contractor, and a presentation is unnecessary for an urgent repair."}'::jsonb),
('business:3-3-communication-in-business:mcq:c75a4620', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "Which one of the following is NOT a potential benefit of improving communication between a business and its customers?", "options": ["Better customer service", "Greater market share", "Higher chances of survival", "Increased risk"]}'::jsonb, '{"answer": 3, "explain": "Increased risk is a potential consequence of poor communication, not better communication. Improved communication leads to better customer service, greater market share, and higher chances of survival — all business benefits."}'::jsonb),
('business:3-3-communication-in-business:mcq:89c8d7f3', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'mcq', 'mcq', 1, '{"question": "A farmer urgently needs a spare part for a tractor but doesn''t know its name or code. Which is the best communication method?", "options": ["Post on social media that the tractor has broken down", "Send a letter showing a sketch of the part", "Send an email to the parts supplier attaching a photo of the part", "Upload a video to the farm website showing how important the tractor is"]}'::jsonb, '{"answer": 2, "explain": "An email with a photo of the part is best because it is FAST (urgent situation), VISUAL (no need to know the name/code), and sent directly to the supplier. A letter is too slow, social media doesn''t reach the supplier, and a website video is irrelevant."}'::jsonb),
('business:3-3-communication-in-business:tf:d23852f2', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Digital communication is always better than non-digital methods such as meetings."}'::jsonb, '{"answer": false, "explain": "FALSE — this is a key examiner trap. Meetings allow immediate feedback, body language, and real-time discussion. Digital communication has disadvantages such as technology failure and inability to convey body language."}'::jsonb),
('business:3-3-communication-in-business:tf:e7c0e60c', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "One-way communication is useful for situations where a response is not required."}'::jsonb, '{"answer": true, "explain": "Correct. One-way communication is suited to giving information to large numbers of people — e.g. a tannoy announcement, an advertising leaflet, or a broadcast email — where no reply is needed."}'::jsonb),
('business:3-3-communication-in-business:tf:db784b53', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Horizontal communication takes place between people on different levels of the hierarchy."}'::jsonb, '{"answer": false, "explain": "HORIZONTAL communication is between people at the SAME level of the hierarchy. Communication between DIFFERENT levels is VERTICAL (either upward or downward)."}'::jsonb),
('business:3-3-communication-in-business:tf:908d3528', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "The development of digital communication has benefited all workers."}'::jsonb, '{"answer": false, "explain": "FALSE and a key examiner point. Some workers lost jobs as productivity increased and automation replaced roles. Others had to retrain. Blockbuster staff, shelf-label workers, and bank tellers are examples of roles reduced by digital change."}'::jsonb),
('business:3-3-communication-in-business:tf:c3be5d0b', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "A website operates 24 hours a day, seven days a week."}'::jsonb, '{"answer": true, "explain": "Correct. This is a key advantage of websites — they allow customers to access information and place orders at any time, without the business needing staff available."}'::jsonb),
('business:3-3-communication-in-business:tf:32fc4ff1', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Email is the best method of communication for ALL business situations."}'::jsonb, '{"answer": false, "explain": "The best method depends on the situation: purpose, audience, urgency, and sensitivity. For example, a phone call is better for urgent issues, and face-to-face is better for sensitive HR discussions. No single method is always best."}'::jsonb),
('business:3-3-communication-in-business:tf:0b7c60d0', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Formal communication uses official channels such as letters, official meetings, and reports."}'::jsonb, '{"answer": true, "explain": "Correct. Formal communication follows set procedures and official channels. It contrasts with informal communication, which occurs outside these channels (e.g. chatting at lunch)."}'::jsonb),
('business:3-3-communication-in-business:tf:fbd5593b', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Social media can only be used for external communication with customers."}'::jsonb, '{"answer": false, "explain": "Social media can also be used for INTERNAL communication. Groups of workers can use platforms to message each other, arrange meetings, share ideas, and receive instructions — especially useful across multiple locations."}'::jsonb),
('business:3-3-communication-in-business:tf:c59c757a', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "A disadvantage of verbal communication is that there is no permanent record unless minutes or a recording are made."}'::jsonb, '{"answer": true, "explain": "Correct. This is a key disadvantage of verbal communication. If a dispute arises about what was said, there is no evidence unless someone took minutes or a recording was made."}'::jsonb),
('business:3-3-communication-in-business:tf:eaeccd06', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "The percentage increase from £250,000 to £525,000 is approximately 110%."}'::jsonb, '{"answer": true, "explain": "Correct. (£525,000 − £250,000) ÷ £250,000 × 100 = £275,000 ÷ £250,000 × 100 = 110%. Since the value more than doubled, the answer must exceed 100%."}'::jsonb),
('business:3-3-communication-in-business:tf:b9e36720', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Blockbuster is an example of a business that thrived due to the digital communication revolution."}'::jsonb, '{"answer": false, "explain": "Blockbuster FAILED because of the digital communication revolution. Netflix''s online streaming service replaced Blockbuster''s DVD rental model. Blockbuster was too slow to adapt and went out of business."}'::jsonb),
('business:3-3-communication-in-business:tf:04402fd9', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "The Chatsworth Estate accountant case study shows that digital technology allowed one accountant to handle 20 times the business revenue."}'::jsonb, '{"answer": true, "explain": "Correct. Michael Isherwood started as the only accountant. Business revenues grew by twenty times but when he retired, there was only one other accountant alongside him. Digital technology transformed productivity in the finance function."}'::jsonb),
('business:3-3-communication-in-business:tf:2c7c4a0f', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "For a recommendation question, simply choosing one method scores full marks."}'::jsonb, '{"answer": false, "explain": "Choosing one method gives only 1 mark. For the other 2 marks, students must provide a COMPARATIVE justification — explaining why the chosen method is better THAN the other method — ideally using case study context for full marks."}'::jsonb),
('business:3-3-communication-in-business:tf:a01d70a1', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tf', 'tf', 1, '{"question": "Amazon''s use of robots in warehouses is an example of digital communication influencing operations."}'::jsonb, '{"answer": true, "explain": "Correct. Once an order is received, it is communicated digitally to a robot which retrieves the product. This has automated operations, reduced errors, sped up dispatch, and reduced labour costs — all impacts of digital communication on business operations."}'::jsonb),
('business:3-3-communication-in-business:learn:a6f21713', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "Core Terminology", "reading": "<ul>\n<li><strong>Communication</strong> — the transmission of a message from a sender to a receiver through a means of communication</li>\n<li><strong>Verbal communication</strong> — communicating by speaking: in meetings, on the telephone, by video-conferencing, or through a presentation</li>\n<li><strong>Written communication</strong> — communication by written words: text, email, and letters</li>\n<li><strong>Digital communication</strong> — the electronic exchange of information using ICT (voice, text, diagrams, pictures, video)</li>\n<li><strong>Feedback</strong> — the response made by a person who receives a communication, indicating they have (or have not) understood it</li>\n<li><strong>Internal communication</strong> — communication between people employed in the same organisation</li>\n<li><strong>External communication</strong> — communication between people in an organisation and others outside it</li>\n<li><strong>Formal communication</strong> — communication through official channels (e.g. letters, official meetings, reports)</li>\n<li><strong>Informal communication</strong> — communication outside official channels (e.g. conversations in a break)</li>\n<li><strong>Social media</strong> — online applications that allow people to create and share content to participate in social networking</li>\n<li><strong>Website</strong> — an online location with several pages that can be contacted by internet users through its address</li>\n</ul>", "question": "Which term describes communication between people employed in the same organisation?", "options": ["Internal communication", "External communication", "Formal communication", "Feedback"]}'::jsonb, '{"answer": 0, "explain": "Internal communication is defined as communication between people employed in the same organisation, unlike external communication which involves people outside it."}'::jsonb),
('business:3-3-communication-in-business:learn:7cace3f2', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "One-way, Two-way & Direction of Communication", "reading": "<p><strong>One-way communication:</strong> the message is sent but there is no reply. Good for giving information to large numbers of people (e.g. a tannoy announcement, an advertising leaflet). Examples: email broadcast, website, social media post.</p>\n<p><strong>Two-way communication:</strong> the receiver can reply to the sender. Important because:</p>\n<ul>\n<li>Feedback confirms the message has been received and understood</li>\n<li>It is good for generating ideas and solving problems</li>\n</ul>\n<p><strong>Vertical communication:</strong> between people on different layers of the hierarchy — either downward (manager to worker) or upward (worker to manager).</p>\n<p><strong>Horizontal communication:</strong> between people at the same level within the organisation structure (e.g. two managers in different departments).</p>\n<p><strong>Internal vs External:</strong> Internal = within the organisation. External = between someone inside the organisation and someone outside it (e.g. a supplier, customer, or government body).</p>", "question": "Communication between two managers who work at the same level in different departments is an example of which type of communication?", "options": ["Horizontal communication", "Vertical communication", "One-way communication", "External communication"]}'::jsonb, '{"answer": 0, "explain": "Horizontal communication takes place between people at the same level within the organisation structure, whereas vertical communication moves up or down the hierarchy."}'::jsonb),
('business:3-3-communication-in-business:learn:cba74c78', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "Verbal Communication — Methods, Advantages & Disadvantages", "reading": "<p><strong>Examples:</strong> phone calls, meetings (in person or via Teams/Zoom), presentations</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages</div>\n<div class=\"pro-item\">Can check the message has been understood by asking for feedback immediately</div>\n<div class=\"pro-item\">Tone of voice and body language can emphasise key points</div>\n<div class=\"pro-item\">Can use diagrams, pictures, slides to support the message</div>\n<div class=\"pro-item\">Meetings — minutes provide a record; ideas can be generated and problems solved</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages</div>\n<div class=\"con-item\">No permanent record (unless minutes taken or recording made)</div>\n<div class=\"con-item\">With large audiences, hard to check everyone has heard or understood</div>\n<div class=\"con-item\">Receiver may disrupt or interrupt the message</div>\n<div class=\"con-item\">Some forms (e.g. travel for international meetings) can be expensive</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Meetings</strong> can be formal (with an agenda and chairperson) or informal (impromptu, no agenda). Online meetings via Teams or Zoom save travel costs.</p>\n<p><strong>Presentations</strong> may use PowerPoint to support visual explanation; the speaker can respond to questions.</p>", "question": "What is a key disadvantage of verbal communication such as a phone call or meeting?", "options": ["There is usually no permanent record unless minutes are taken", "It cannot use tone of voice to emphasise key points", "Feedback cannot be given immediately", "It is never a suitable method for solving business problems"]}'::jsonb, '{"answer": 0, "explain": "The card lists the lack of a permanent record (unless minutes are taken or a recording made) as a disadvantage of verbal communication."}'::jsonb),
('business:3-3-communication-in-business:learn:9c2099a4', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "Written Communication — Letters, Emails, Texts", "reading": "<p><strong>Letters:</strong> formal, provide a physical record; can be sent by recorded delivery; often used for contracts or legal documents.</p>\n<p><strong>Emails and texts:</strong> fast, widely used; can be sent to one or many people; disadvantage is that bulk emails are often ignored or sent to spam.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages of Written</div>\n<div class=\"pro-item\">There is a record of the message</div>\n<div class=\"pro-item\">Receiver can read and re-read to check understanding</div>\n<div class=\"pro-item\">Can be sent to multiple people at once</div>\n<div class=\"pro-item\">Can avoid confrontation</div>\n<div class=\"pro-item\">Text and email are very fast</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages of Written</div>\n<div class=\"con-item\">Cannot immediately check receiver has understood</div>\n<div class=\"con-item\">Success depends on how clearly it has been written</div>\n<div class=\"con-item\">Risk of virus infection from email attachments</div>\n<div class=\"con-item\">Emails can get lost in spam</div>\n<div class=\"con-item\">Some people get overwhelmed by volume of emails</div>\n</div>\n</div>", "question": "Which of these is a specific advantage of written communication compared with verbal communication?", "options": ["It leaves a permanent record the receiver can re-read", "It allows the sender to check understanding immediately", "Tone of voice can be used to emphasise key points", "It is always cheaper than any other method"]}'::jsonb, '{"answer": 0, "explain": "The card states that written communication leaves a record of the message and lets the receiver read and re-read it to check understanding, unlike verbal communication."}'::jsonb),
('business:3-3-communication-in-business:learn:8edc2890', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "Social Media & Websites", "reading": "<p><strong>Social media</strong> (Facebook, Instagram, Twitter/X, Pinterest): online platforms for sharing communication.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages</div>\n<div class=\"pro-item\">Huge number of users — massive reach for advertising</div>\n<div class=\"pro-item\">Information can be updated regularly</div>\n<div class=\"pro-item\">Visual images enhance communications</div>\n<div class=\"pro-item\">Cheaper than traditional media (TV, radio, print)</div>\n<div class=\"pro-item\">Allows customer feedback and interaction</div>\n<div class=\"pro-item\">Good for internal staff communication across locations</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages</div>\n<div class=\"con-item\">Needs managing — updating and responding costs time and money</div>\n<div class=\"con-item\">Difficult to measure the effectiveness of campaigns</div>\n</div>\n</div>\n<p style=\"margin-top:8px;\"><strong>Websites:</strong> operate 24/7; can take online orders; detailed product information; customers use search engines to find them; can be built and maintained cheaply. Risks: website crashing, spam, needs regular updating.</p>\n<p><strong>Targeting note:</strong> 90% of Instagram users are under 35 — good for reaching young audiences. Pinterest is popular with women and used for DIY, fashion, food.</p>", "question": "Which of the following is a genuine disadvantage of using social media for business communication?", "options": ["It is difficult to measure the effectiveness of campaigns", "It cannot be updated regularly", "It cannot be used for internal staff communication", "It has a very limited reach compared with traditional media"]}'::jsonb, '{"answer": 0, "explain": "The card lists difficulty measuring the effectiveness of campaigns as a disadvantage, while its advantages include huge reach, regular updating and internal staff use."}'::jsonb),
('business:3-3-communication-in-business:learn:dbce4368', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "Importance of Communication in Each Functional Area", "reading": "<p><strong>Marketing:</strong> external communication for market research and advertising; internal communication for planning promotional campaigns</p>\n<p><strong>Finance:</strong> external communication to arrange bank loans; internal communication about income and expenditure to keep accurate accounts; digital tools have made invoicing, payments and financial reporting much faster (e.g. Quickbooks app)</p>\n<p><strong>Human Resources:</strong> external and internal communication for recruitment and selection; internal communication to resolve workplace problems, motivate workers, appraise performance</p>\n<p><strong>Operations / Production:</strong> internal communication about quality to reduce waste; marketing informs production about orders placed; external communication to enquire about raw material deliveries</p>\n<p><strong>Government and Trade:</strong> external communication to understand regulations; to apply for government grants</p>\n<p><strong>Choosing the right method:</strong> consider WHO you are communicating with, the PURPOSE of the communication, and what methods are AVAILABLE and AFFORDABLE. Internal vs external, size of audience, urgency, and sensitivity all affect the choice.</p>", "question": "According to the card, alongside who you are communicating with and what methods are available and affordable, what else should a business consider when choosing a communication method?", "options": ["The purpose of the communication", "The age of the business", "The colour scheme of the company logo", "The total number of shareholders"]}'::jsonb, '{"answer": 0, "explain": "The card states that a business should consider WHO it is communicating with, the PURPOSE of the communication, and what methods are AVAILABLE and AFFORDABLE."}'::jsonb),
('business:3-3-communication-in-business:learn:49433a8d', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'learn', 'mcq', 1, '{"readingTitle": "How Digital Communication Influences Business Activity", "reading": "<p><strong>Marketing:</strong> websites and social media allow businesses to reach millions globally; online selling has reduced the need for physical shops (e.g. Amazon, eBay); competition has increased as customers can compare prices more easily</p>\n<p><strong>Finance:</strong> invoices and payments sent more quickly; accounting information stored and processed digitally; financial reports prepared faster (Chatsworth Estate case study — one accountant handled 20× the business)</p>\n<p><strong>HR:</strong> jobs advertised on websites; applications and invitations by email; interviews by video-conferencing (Zoom/Teams); more staff working from home or while mobile; some jobs lost as productivity increased; workers required to retrain</p>\n<p><strong>Operations:</strong> production highly automated via robots; quality control improved (machines inspect and relay data); production is leaner — can be reprogrammed quickly in response to demand changes; GPS tracking of delivery drivers; staff monitoring via keyloggers, Microsoft Teams log-on records</p>\n<p><strong>Overall:</strong> digital communication has increased competition, enabled globalisation, reduced costs, and created new business opportunities (hardware makers, programmers, ICT trainers). Not all businesses have survived — some slow to adapt have closed (e.g. Blockbuster).</p>", "question": "What does the closure of businesses such as Blockbuster during the rise of digital communication demonstrate?", "options": ["Some businesses fail if they are too slow to adapt to digital change", "Digital communication has no effect on business survival", "Only marketing departments are affected by digital communication", "All traditional retailers are guaranteed to close eventually"]}'::jsonb, '{"answer": 0, "explain": "The card notes that not all businesses have survived the digital communication revolution — some, like Blockbuster, were too slow to adapt and closed."}'::jsonb),
('business:3-3-communication-in-business:misc:ac308a22', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Digital communication is always better than non-digital communication.</p><p><strong>✅ The correct idea:</strong> Digital communication is NOT always better. Face-to-face meetings allow immediate feedback, body language, and real-time discussion. They are better for sensitive issues (e.g. disciplinary matters, appraisals) and for building relationships. The OCR examiner regularly flags this as a FALSE statement in multiple-choice questions.</p>", "question": "Why might a face-to-face meeting be a better method than digital communication for a sensitive disciplinary matter?", "options": ["It gives immediate feedback and allows body language to be used", "Digital communication is always better regardless of the situation", "Meetings automatically create a permanent written record", "Meetings are always the cheapest communication method"]}'::jsonb, '{"answer": 0, "explain": "The correct concept is that digital communication is not always better — meetings allow immediate feedback and body language, making them more suitable for sensitive issues."}'::jsonb),
('business:3-3-communication-in-business:misc:f50afd7e', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> All workers have benefited from the development of digital communication.</p><p><strong>✅ The correct idea:</strong> Digital communication has NOT benefited ALL workers. While many gained new opportunities, flexibility, and higher productivity, others lost their jobs as automation replaced them (e.g. shelf-label workers at Leclerc, DVD rental staff at Blockbuster). Some have had to undergo retraining to stay employed. Examiners specifically test this.</p>", "question": "Which statement correctly describes the overall impact of digital communication on workers?", "options": ["Some workers gained flexibility, others lost jobs to automation", "All workers have benefited with no negative effects at all", "Digital communication has had no effect on employment", "Only office-based workers have been affected by digital change"]}'::jsonb, '{"answer": 0, "explain": "The correct concept is that digital communication has NOT benefited all workers — some gained flexibility while others lost jobs to automation and had to retrain."}'::jsonb),
('business:3-3-communication-in-business:misc:4f6bd535', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Internal communication only goes downward — from managers to workers.</p><p><strong>✅ The correct idea:</strong> Internal communication can be VERTICAL (both upward AND downward) or HORIZONTAL. Upward communication goes from worker to manager. Horizontal communication goes between people at the same level (e.g. two department managers). Only treating communication as one-directional will cost marks.</p>", "question": "In which directions can internal communication travel within a business?", "options": ["Vertically (upward and downward) and horizontally", "Only downward, from managers to workers", "Only upward, from workers to managers", "Only horizontally, between people at the same level"]}'::jsonb, '{"answer": 0, "explain": "Internal communication can be vertical (upward or downward) or horizontal (between people at the same level), not just one-directional."}'::jsonb),
('business:3-3-communication-in-business:misc:9c9ea3f8', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Email is always the best method of communication for businesses.</p><p><strong>✅ The correct idea:</strong> The best method depends on the situation: who is being communicated with, the purpose, and what is available. For urgent issues needing immediate two-way discussion, a phone call may be better. For sensitive HR issues, face-to-face is preferred. For reaching thousands of customers, social media or a website may be best.</p>", "question": "What determines the best method of communication for a business to use in a given situation?", "options": ["Who is being communicated with, the purpose, and what is available", "Email should always be used because it is the fastest method", "The cheapest method should always be chosen regardless of purpose", "Whichever method the sender personally prefers"]}'::jsonb, '{"answer": 0, "explain": "The correct concept is that the best method depends on the situation — who is being contacted, the purpose, and what is available — not that one method (like email) is always best."}'::jsonb),
('business:3-3-communication-in-business:misc:2ea0f75c', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Social media is only useful for communicating with customers externally.</p><p><strong>✅ The correct idea:</strong> Social media can also be used for INTERNAL communications. Groups of workers can be linked through social media platforms to message each other, arrange meetings, share ideas, and receive instructions — especially useful for staff spread across multiple locations or working remotely.</p>", "question": "Besides communicating with customers, how else can a business use social media?", "options": ["As a tool for internal communication between workers across locations", "It cannot be used for any purpose other than customer communication", "Only for one-way announcements with no internal use", "It can only be used by businesses with a single location"]}'::jsonb, '{"answer": 0, "explain": "The correct concept is that social media can also be used for internal communication, linking workers across multiple locations or remote working."}'::jsonb),
('business:3-3-communication-in-business:misc:ebe21a15', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A meeting is always a disadvantage because it takes time and costs money.</p><p><strong>✅ The correct idea:</strong> Meetings have both advantages AND disadvantages. Advantages include immediate feedback, the ability to check understanding, discussion and idea generation, and the use of body language. Minutes provide a formal record. Online meetings (Teams, Zoom) reduce travel costs. Never say any method is purely good or bad — evaluation is always expected.</p>", "question": "What is the correct evaluative view of meetings as a communication method?", "options": ["Meetings have both advantages, like feedback, and disadvantages, like cost", "Meetings are always a disadvantage because they take time and cost money", "Meetings have no disadvantages when held online", "Meetings should never be used to generate ideas or solve problems"]}'::jsonb, '{"answer": 0, "explain": "The card stresses that meetings have both advantages (immediate feedback, discussion, minutes as a record) and disadvantages (time, cost) — no method should be judged as purely good or bad."}'::jsonb),
('business:3-3-communication-in-business:tips:9f785d5c', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Analyse one advantage of a specific communication method (3 marks)", "reading": "Structure: (U) Identify a specific advantage of the METHOD — e.g. ''emails can be referred back to.'' (APP) Link to the specific business in the case study. (AN) Show the business-facing impact — e.g. ''this could improve customer service and reduce the risk of losing sales to competitors.'' CRITICAL: do NOT just describe what the method does — state the ADVANTAGE FOR THE BUSINESS.", "question": "In a 3-mark ''analyse one advantage of a communication method'' question, what is the critical error to avoid?", "options": ["Describing the method instead of stating its advantage", "Naming the specific method being used", "Linking the answer to the case study business", "Explaining the business-facing impact of the advantage"]}'::jsonb, '{"answer": 0, "explain": "The card warns that students must NOT just describe what the method does — they must state the actual advantage FOR THE BUSINESS to score analysis marks."}'::jsonb),
('business:3-3-communication-in-business:tips:39456cd2', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Recommend which method of communication to use (3 marks)", "reading": "Structure: (1 mark) Make a clear recommendation — ''SJ Salon should use a weekly email.'' (2 marks) Justify by comparing the two methods — your reason must explain why the chosen method is BETTER THAN the other. The justification must cover BOTH methods and be contextual (use case study detail). E.g. ''Three employees work part-time so finding a time when everyone can attend a meeting will be difficult — an email can be read at any time.''", "question": "In a 3-mark ''recommend which method of communication to use'' question, what must the justification for the remaining 2 marks include?", "options": ["A contextual comparison of why the chosen method is better", "Just a restatement of the method that was chosen", "A list of every possible communication method available", "A generic advantage with no reference to the case study"]}'::jsonb, '{"answer": 0, "explain": "The card requires the justification to compare BOTH methods, explaining why the chosen one is better than the other, using case study detail."}'::jsonb),
('business:3-3-communication-in-business:tips:20acd689', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Analyse how digital communication has affected workers (6 marks)", "reading": "Two separate U→APP→AN chains, each worth 3 marks. Effect 1 (positive): e.g. working from home → more flexibility → better work-life balance → lower absenteeism. Effect 2 (negative): e.g. digital automation replaces jobs → workers made redundant → increased unemployment. Always show both sides for balance — the examiner rewards nuance.", "question": "For a 6-mark ''analyse how digital communication has affected workers'' question, what structure is expected?", "options": ["Two chains of impact, one positive and one negative", "One long chain covering six unrelated points", "Six short one-sentence points with no development", "A single paragraph focused only on positive effects"]}'::jsonb, '{"answer": 0, "explain": "The card explains the answer should have two separate U→APP→AN chains, each worth 3 marks, showing both a positive and a negative effect for balance."}'::jsonb),
('business:3-3-communication-in-business:tips:b9852582', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Calculation Warning — Percentage change calculations", "reading": "Formula: (New Value − Original Value) ÷ Original Value × 100. Example: £250,000 to £525,000 = (£525,000 − £250,000) ÷ £250,000 × 100 = 110%. The most common mistake is dividing by the NEW value instead of the ORIGINAL. If the value more than doubles, the answer MUST be over 100%.", "question": "When calculating percentage change, what is the most common mistake students make according to this tip?", "options": ["Dividing by the new value instead of the original value", "Adding the two values together instead of subtracting them", "Forgetting to multiply the result by 100", "Rounding the original value before subtracting"]}'::jsonb, '{"answer": 0, "explain": "The card warns that the formula requires dividing by the ORIGINAL value, and the most common mistake is dividing by the NEW value instead."}'::jsonb),
('business:3-3-communication-in-business:tips:83cc1208', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Explain Question (2 marks) — Explain one reason why communication is important for a business", "reading": "Structure: (K) Give a reason — e.g. ''Communication is important for marketing.'' (U) Explain why — e.g. ''so that customers know about what the business sells and can be persuaded to buy.'' The question does NOT require application to a specific business unless it says ''explain why THIS business...'' — read carefully.", "question": "For a 2-mark ''explain one reason why communication is important'' question, what does the mark scheme require?", "options": ["A reason (K) followed by an explanation of why it matters (U)", "A reason plus application to a named business in every case", "Three separate developed points with case study detail", "Only a definition of the word ''communication''"]}'::jsonb, '{"answer": 0, "explain": "The card gives the structure as (K) a reason followed by (U) an explanation of why, and notes application is only needed if the question specifically asks about a named business."}'::jsonb),
('business:3-3-communication-in-business:tips:86b59da0', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Examiner Warning — Always name the specific advantage — not just the method", "reading": "A very common error: writing ''email is a good method'' or ''meetings allow communication'' without stating WHAT the advantage is or WHY it helps the business. Examiners explicitly penalise vague responses. ''Quick and easy'' alone scores zero. State the specific feature: ''can be sent to multiple recipients at once'' or ''can be referred back to for clarification.''", "question": "Why would the answer ''email is a good method because it''s quick and easy'' score zero marks?", "options": ["It fails to state a specific advantage or explain how it helps", "Email is not accepted as a valid communication method by examiners", "It does not mention a named business from the case study", "The sentence is grammatically incorrect"]}'::jsonb, '{"answer": 0, "explain": "The card explains that vague responses like ''quick and easy'' are penalised because they do not state the specific feature or advantage for the business."}'::jsonb),
('business:3-3-communication-in-business:tips:74a54067', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Key Examiner Warning — Analysis must be business-facing", "reading": "Analysis marks are only awarded for impacts on the BUSINESS — such as effects on revenue, profit, market share, costs, customer service, employee retention, reputation, or productivity. Writing ''employees will feel more motivated'' scores as analysis. Writing ''better communication'' does NOT — it just restates the question. Always push to the business consequence.", "question": "According to the mark scheme, which type of statement counts as valid analysis in a communication question?", "options": ["A statement showing a business-facing impact, e.g. motivation", "A statement that just restates ''communication has improved''", "A statement describing how the method technically works", "A statement about a competitor''s pricing strategy"]}'::jsonb, '{"answer": 0, "explain": "The card states analysis marks require a business-facing impact — ''employees will feel more motivated'' scores as analysis, whereas ''better communication'' just restates the question and does not."}'::jsonb),
('business:3-3-communication-in-business:tips:8918bc0b', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'tips', 'mcq', 1, '{"readingTitle": "Evaluation Tip — Evaluating the influence of digital communication", "reading": "For evaluate questions on digital communication, present BOTH benefits (lower costs, wider reach, globalisation, new products like Netflix) AND drawbacks (job losses, businesses that failed to adapt, workers needing retraining, increased competition). Conclude with a justified judgement — e.g. ''on balance, digital communication has been positive for most businesses because the cost savings and market reach outweigh the disruption.''", "question": "What must a strong evaluation answer on the influence of digital communication include?", "options": ["Both benefits and drawbacks, ending with a justified judgement", "Only the benefits, since digital communication is generally positive", "A list of communication methods with no conclusion", "A conclusion stating an opinion with no supporting reasons"]}'::jsonb, '{"answer": 0, "explain": "The card requires presenting BOTH benefits and drawbacks of digital communication, then concluding with a justified judgement, not a one-sided answer."}'::jsonb),
('business:3-3-communication-in-business:fib:f0f1b736', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'fib', 'fib', 2, '{"question": "Communication is the _____ of a message from a sender to a receiver. When the receiver can reply, it is known as _____ communication.", "blankOptions": {"B1": ["leaner", "transmission", "feedback", "24/7"], "B2": ["horizontal", "vertical", "social media", "two-way"]}}'::jsonb, '{"blanks": {"B1": "transmission", "B2": "two-way"}}'::jsonb),
