('business:3-3-communication-in-business:fib:d94e2dc8', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'fib', 'fib', 2, '{"question": "Finance departments can store and process _____ information more quickly. Marketing departments use websites and _____ to reach potentially huge markets.", "blankOptions": {"B1": ["one-way", "competition", "accounting", "leaner"], "B2": ["social media", "costs", "electronically", "feedback"]}}'::jsonb, '{"blanks": {"B1": "accounting", "B2": "social media"}}'::jsonb),
('business:3-3-communication-in-business:fib:37db8576', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'fib', 'fib', 3, '{"question": "Human resource departments have seen more staff working while _____ or working from _____. Some workers have lost their jobs or had to undergo _____.", "blankOptions": {"B1": ["mobile", "informal", "competition", "website"], "B2": ["formal", "home", "productivity", "competition"], "B3": ["social media", "formal", "retraining", "one-way"]}}'::jsonb, '{"blanks": {"B1": "mobile", "B2": "home", "B3": "retraining"}}'::jsonb),
('business:3-3-communication-in-business:fib:4a93a461', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'fib', 'fib', 2, '{"question": "A _____ is an online location that links pages of information. It allows sales to be made online and operates _____.", "blankOptions": {"B1": ["competition", "social media", "website", "home"], "B2": ["accounting", "mobile", "24/7", "transmission"]}}'::jsonb, '{"blanks": {"B1": "website", "B2": "24/7"}}'::jsonb),
('business:3-3-communication-in-business:match:b6f848c5', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Communication”?", "options": ["Communication where the receiver can reply to the sender, allowing feedback and discussion", "Communication between people on different layers of the organisational hierarchy — either upward or downward", "Communication between people at the same level within the organisation structure", "The transmission of a message from a sender to a receiver through a means of communication"]}'::jsonb, '{"answer": 3, "explain": "“Communication” means: The transmission of a message from a sender to a receiver through a means of communication"}'::jsonb),
('business:3-3-communication-in-business:match:66bc7a56', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Two-way communication”?", "options": ["Communication between people on different layers of the organisational hierarchy — either upward or downward", "Communication between people at the same level within the organisation structure", "Communication that uses the official channels of an organisation, such as letters, official meetings, and reports", "Communication where the receiver can reply to the sender, allowing feedback and discussion"]}'::jsonb, '{"answer": 3, "explain": "“Two-way communication” means: Communication where the receiver can reply to the sender, allowing feedback and discussion"}'::jsonb),
('business:3-3-communication-in-business:match:53b8b7f1', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Vertical communication”?", "options": ["Communication between people at the same level within the organisation structure", "Communication between people on different layers of the organisational hierarchy — either upward or downward", "Communication that uses the official channels of an organisation, such as letters, official meetings, and reports", "The electronic exchange of information using ICT — including voice, text, images and video"]}'::jsonb, '{"answer": 1, "explain": "“Vertical communication” means: Communication between people on different layers of the organisational hierarchy — either upward or downward"}'::jsonb),
('business:3-3-communication-in-business:match:ba2df6c5', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Horizontal communication”?", "options": ["Communication that uses the official channels of an organisation, such as letters, official meetings, and reports", "Communication between people at the same level within the organisation structure", "The electronic exchange of information using ICT — including voice, text, images and video", "Online applications that allow people to create and share content to participate in social networking"]}'::jsonb, '{"answer": 1, "explain": "“Horizontal communication” means: Communication between people at the same level within the organisation structure"}'::jsonb),
('business:3-3-communication-in-business:match:9bc3adbc', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Formal communication”?", "options": ["Communication that uses the official channels of an organisation, such as letters, official meetings, and reports", "The electronic exchange of information using ICT — including voice, text, images and video", "Online applications that allow people to create and share content to participate in social networking", "The response made by the receiver of a communication indicating whether they have understood the message"]}'::jsonb, '{"answer": 0, "explain": "“Formal communication” means: Communication that uses the official channels of an organisation, such as letters, official meetings, and reports"}'::jsonb),
('business:3-3-communication-in-business:match:e6ba3f5e', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Digital communication”?", "options": ["Online applications that allow people to create and share content to participate in social networking", "The electronic exchange of information using ICT — including voice, text, images and video", "The response made by the receiver of a communication indicating whether they have understood the message", "The transmission of a message from a sender to a receiver through a means of communication"]}'::jsonb, '{"answer": 1, "explain": "“Digital communication” means: The electronic exchange of information using ICT — including voice, text, images and video"}'::jsonb),
('business:3-3-communication-in-business:match:b826cca0', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Social media”?", "options": ["Online applications that allow people to create and share content to participate in social networking", "The response made by the receiver of a communication indicating whether they have understood the message", "The transmission of a message from a sender to a receiver through a means of communication", "Communication where the receiver can reply to the sender, allowing feedback and discussion"]}'::jsonb, '{"answer": 0, "explain": "“Social media” means: Online applications that allow people to create and share content to participate in social networking"}'::jsonb),
('business:3-3-communication-in-business:match:bec4475e', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Feedback”?", "options": ["The transmission of a message from a sender to a receiver through a means of communication", "Communication where the receiver can reply to the sender, allowing feedback and discussion", "The response made by the receiver of a communication indicating whether they have understood the message", "Communication between people on different layers of the organisational hierarchy — either upward or downward"]}'::jsonb, '{"answer": 2, "explain": "“Feedback” means: The response made by the receiver of a communication indicating whether they have understood the message"}'::jsonb),
('business:3-4-recruitment-and-selection:exam:4d1175c0', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'exam', 'mcq', 1, '{"num": "QUESTION 01", "question": "What would be included in the job description for a hospital doctor?", "options": ["A list of the medical qualifications required", "An ability to listen carefully to patients'' concerns", "Previous experience of working in a hospital", "The main duties of medical staff when working in a hospital"], "hint": "A job description is about the TASKS and DUTIES of the job — not about the personal attributes or qualifications of the person doing it.", "starter": "A job description includes..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p>Answer: <strong>D — The main duties of medical staff when working in a hospital.</strong></p><p>A job description lists the duties, tasks and responsibilities of the role. Qualifications (A), personal qualities (B) and experience (C) all belong in the person specification.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:d4f9a09f', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Which of the following is an example of external recruitment?", "options": ["Promoting a worker from another department", "Emailing staff about a vacancy", "Advertising in a national newspaper", "Putting a notice on the company intranet"]}'::jsonb, '{"answer": 2, "explain": "External recruitment means filling a vacancy with someone from outside the organisation. Advertising in a national newspaper is an external method. The other options are all internal methods."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:4bb34fd5', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "A job description includes which of the following?", "options": ["The qualifications required by the applicant", "The main duties and responsibilities of the worker", "The personal qualities the worker must have", "The experience needed to perform the job"]}'::jsonb, '{"answer": 1, "explain": "A job description lists the duties, tasks and responsibilities of the worker. Qualifications, personal qualities and experience needed belong in the person specification."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:f6784020', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Which item belongs in a person specification?", "options": ["The main tasks of the job", "The name of the line manager", "The hours of work", "The skills and qualifications needed"]}'::jsonb, '{"answer": 3, "explain": "A person specification lists the qualities, qualifications and knowledge a person should have. Tasks, line manager details and hours of work belong in the job description."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:b969f20d', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Danielle advertises on Indeed at 60p per click. 350 people click on the advert and she contacts 16 applicants at £1 each. What is the total cost?", "options": ["£226", "£262", "£622", "£227"]}'::jsonb, '{"answer": 1, "explain": "350 × £0.60 = £210. 16 × £1 = £16. Total = £210 + £16 = £226. Answer: A. (Note: the original OCR answer is A = £226.)"}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:0e524d80', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Which of the following would be used to shortlist candidates?", "options": ["Interview", "Group activity", "Letter of application", "Reference"]}'::jsonb, '{"answer": 2, "explain": "Letters of application (along with CVs and application forms) are used to create a shortlist. Interviews, group activities and references are used at the final selection stage."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:f420f545', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Which of the following is an advantage for a business of using a CV rather than an application form?", "options": ["Applicants are less likely to leave out essential information", "It shows an applicant''s ability to organise relevant information", "It ensures all applicants provide the same information", "It is easier for the business to compare applicants"]}'::jsonb, '{"answer": 1, "explain": "A CV shows the applicant''s ability to organise information. Application forms are actually better for ensuring all applicants provide the same specific information and for making comparisons."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:a9eb3671', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "A business has a skills gap. Which action would best solve this?", "options": ["Reduce the number of employees", "Advertise internally on the company noticeboard", "Recruit an external specialist with the required skills", "Ask existing employees to work fewer hours"]}'::jsonb, '{"answer": 2, "explain": "A skills gap means the business lacks workers with specific skills. The solution is to recruit externally — specifically seeking someone with those skills from outside the business."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:8b8a6f4a', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Which of the following is a disadvantage of internal recruitment?", "options": ["It takes longer than external recruitment", "Existing staff may not bring fresh ideas", "It is more expensive than external recruitment", "Workers need more induction training"]}'::jsonb, '{"answer": 1, "explain": "A key disadvantage of internal recruitment is that existing staff may not add new ideas to help the business improve. Internal recruitment is actually cheaper and faster than external."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:381d291a', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Waitrose uses interviews, group activities and tests in its selection process. Which method is best for assessing how well a candidate works in a team?", "options": ["Interview", "Group activity", "Test", "CV"]}'::jsonb, '{"answer": 1, "explain": "Group activities reveal how well people work with others — their interpersonal skills. Interviews assess communication and presentation; tests assess specific technical skills."}'::jsonb),
('business:3-4-recruitment-and-selection:mcq:17576740', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'mcq', 'mcq', 1, '{"question": "Which of the following is a method of internal recruitment?", "options": ["Advertising in a local newspaper", "Using a recruitment agency", "Posting on the company website for staff", "Advertising in a specialist magazine"]}'::jsonb, '{"answer": 2, "explain": "The company website can be used internally (to notify existing staff) as well as externally. Local newspapers, recruitment agencies and specialist magazines are all external methods."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:210f6c2c', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "A job description lists the qualifications and skills needed for the job."}'::jsonb, '{"answer": false, "explain": "False. A job description lists the duties, tasks and responsibilities of the role. Qualifications and skills belong in the person specification."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:6c44bb8e', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "Internal recruitment is always cheaper and quicker than external recruitment."}'::jsonb, '{"answer": true, "explain": "True. Internal recruitment saves advertising costs and the person can start sooner as they don''t need to give notice elsewhere."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:03264ec0', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "A CV makes it easy for the business to compare applicants because all applicants provide the same information."}'::jsonb, '{"answer": false, "explain": "False. An application form ensures all applicants provide the same information in the same format, making comparison easier. A CV is structured by the applicant."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:d9a61ce8', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "One disadvantage of internal recruitment is that existing staff may not bring fresh ideas to the business."}'::jsonb, '{"answer": true, "explain": "True. This is a key disadvantage of internal recruitment. Fresh ideas and new skills are more likely to come from external candidates."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:9c0138a4', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "References are always a reliable source of information about a candidate."}'::jsonb, '{"answer": false, "explain": "False. Businesses sometimes give workers good references because they want them to leave. This is why organisations often use more than one method of selection."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:9d780d46', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "Group activities are best for assessing a candidate''s ability to work as part of a team."}'::jsonb, '{"answer": true, "explain": "True. Group activities reveal interpersonal skills and how well people work with others — something that is difficult to assess through interviews or tests alone."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:f4dd20ec', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "External recruitment methods include notice boards, word of mouth and emails to staff."}'::jsonb, '{"answer": false, "explain": "False. These are internal recruitment methods. External methods include websites, local/national newspapers, specialist magazines, social media and job centres."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:3745576c', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "A skills gap occurs when a business needs workers with specialist skills it does not currently have."}'::jsonb, '{"answer": true, "explain": "True. A skills gap often arises when new production methods or technologies are introduced, requiring the business to recruit externally for those skills."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:e4a66b9a', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "Interviews are sufficient on their own to make a fully informed recruitment decision."}'::jsonb, '{"answer": false, "explain": "False. Interviews can give the wrong impression, and sometimes applicants are not entirely honest. Organisations often use more than one method of selection to build an accurate picture."}'::jsonb),
('business:3-4-recruitment-and-selection:tf:2c8b4d15', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tf', 'tf', 1, '{"question": "Induction training is needed for both internal and external recruits."}'::jsonb, '{"answer": false, "explain": "False. Induction training is mainly needed for external recruits. An internal recruit already knows the organisation, its aims, and how things work — so induction training may not be needed, saving the business money."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:ede31e95', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Core Terminology", "reading": "<ul>\n<li><strong>Recruitment</strong> — The process of finding people to work in a new or established business</li>\n<li><strong>Selection</strong> — The process of choosing between applicants for a job</li>\n<li><strong>Internal recruitment</strong> — When a job vacancy is filled by employing someone who is already an employee of the business. Methods include notice boards, word of mouth, company website and emails to staff</li>\n<li><strong>External recruitment</strong> — When a job vacancy is filled by employing someone from outside the business. Methods include websites, newspaper, social media and specialist magazines</li>\n<li><strong>Skills gap</strong> — When a business recruits skilled workers because it is short of them</li>\n<li><strong>Job description</strong> — A list of the main duties, tasks and responsibilities of a worker</li>\n<li><strong>Person specification</strong> — A list of the qualities, qualifications and knowledge that a person should have to do a particular job</li>\n<li><strong>Induction training</strong> — Training to introduce a new worker to the business, place of work and their fellow workers as well as their job</li>\n<li><strong>Recruitment agency</strong> — A specialist agency that carries out all the tasks involved in recruitment and selection of workers on behalf of an organisation</li>\n<li><strong>Employment agency</strong> — An agency that has workers readily available for business hire, usually for a short period of time</li>\n<li><strong>CV (curriculum vitae)</strong> — A document on which the applicant outlines their personal details, experience and skills</li>\n<li><strong>Application form</strong> — A form which asks applicants for personal details, experience and skills</li>\n<li><strong>Letter of application</strong> — A letter written by the applicant usually explaining why they think they are suitable for the job</li>\n</ul>", "question": "According to core recruitment terminology, what is ''selection''?", "options": ["The process of choosing between applicants for a job", "The process of finding people to work in a business", "Training a new worker to fit into the business", "A list of duties and responsibilities of a worker"]}'::jsonb, '{"answer": 0, "explain": "Selection is defined as the process of choosing between applicants for a job, distinct from recruitment (finding people to work in the business)."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:afd568e8', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Why Businesses Recruit", "reading": "<p>There are three main reasons why businesses recruit new workers:</p>\n<ul>\n<li><strong>Starting up or growing</strong> — A new business must recruit workers from scratch. A business getting increased orders or making more sales may increase production and need more workers</li>\n<li><strong>To replace staff who leave</strong> — Staff leave for all kinds of reasons: promotion, retirement, to do something different, or because they have been dismissed</li>\n<li><strong>Skills shortage / Skills gap</strong> — May arise as new methods of production are introduced, perhaps using new technology. Recruiting skilled workers can be very difficult, particularly if the economy is doing well. It is not unusual for businesses to look abroad when recruiting skilled workers</li>\n</ul>\n<p><strong>Note from OCR delivery guide:</strong> Sometimes the work can be reallocated amongst other posts to avoid the need to replace the job role. Businesses should not automatically recruit whenever someone leaves.</p>\n<p><strong>Cost of poor recruitment:</strong> Oxford Economics research found replacing a staff member costs on average £30,614. Lost output during the settling-in period (28 weeks on average) accounts for £25,181, with direct recruitment costs of £5,433 covering agency fees, advertising, management time and HR processing.</p>", "question": "According to the OCR delivery guide note, what should a business consider before recruiting a replacement for a worker who has left?", "options": ["Whether the work could be reallocated instead", "Whether to increase the salary of the role", "Whether to close the department entirely", "Whether to promote the departing worker''s manager"]}'::jsonb, '{"answer": 0, "explain": "The card notes work can sometimes be reallocated among other posts, and businesses should not automatically recruit whenever someone leaves."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:3a9e4ef6', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "The Recruitment & Selection Process", "reading": "<p>The recruitment and selection process has two main stages:</p>\n<p><strong>Recruitment stage:</strong></p>\n<ul>\n<li>Step 1: Identify a vacancy</li>\n<li>Step 2: Write a job description</li>\n<li>Step 3: Write a person specification</li>\n<li>Step 4: Advertise the vacancy</li>\n<li>Step 5: Receive applications</li>\n</ul>\n<p><strong>Selection stage:</strong></p>\n<ul>\n<li>Step 6: Shortlist candidates (using CVs, application forms, letters of application)</li>\n<li>Step 7: Carry out interviews / tests / group activities</li>\n<li>Step 8: Make a job offer</li>\n</ul>\n<p><strong>Important distinction:</strong> ''Recruitment'' refers to searching for suitable candidates and attracting them to apply. ''Selection'' refers to vetting candidates to choose the most suitable one.</p>", "question": "Which of the following best describes ''selection'' in the recruitment and selection process?", "options": ["Vetting candidates to choose the most suitable one", "Searching for and attracting suitable candidates to apply", "Writing the job description and person specification", "Advertising the vacancy to attract applicants"]}'::jsonb, '{"answer": 0, "explain": "The card states selection refers to vetting candidates to choose the most suitable person, while recruitment means searching for and attracting candidates."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:ca7f50b2', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Job Description vs Person Specification", "reading": "<p><strong>Job Description</strong> — lists the tasks and responsibilities the worker must perform. It helps the business be clear about what work it wants done, and helps applicants decide if they want to apply.</p>\n<p>A job description typically includes: job title, grade/pay scale, who the person is responsible to, job purpose, and main duties/tasks.</p>\n<p><strong>Person Specification</strong> — states the knowledge, qualifications, experience, personal qualities and skills the worker will need. It helps the business decide what kind of person to appoint and which selection methods to use.</p>\n<p>A person specification typically includes: qualifications (essential/desirable), experience, knowledge/skills/abilities, and special requirements (e.g. driving licence). Each attribute is marked E (essential) or D (desirable) and the method of assessment is noted (AF = application form, I = interview, R = reference, T = test).</p>\n<div class=\"two-col\" style=\"margin-top:10px;\">\n<div>\n<div class=\"col-head\">Job Description Contains</div>\n<div class=\"pro-item\">Job title and department</div>\n<div class=\"pro-item\">Hours of work and location</div>\n<div class=\"pro-item\">Main duties and tasks</div>\n<div class=\"pro-item\">Who the worker reports to</div>\n</div>\n<div>\n<div class=\"col-head\">Person Specification Contains</div>\n<div class=\"pro-item\">Qualifications required</div>\n<div class=\"pro-item\">Experience needed</div>\n<div class=\"pro-item\">Skills and personal qualities</div>\n<div class=\"pro-item\">Special requirements (e.g. can drive)</div>\n</div>\n</div>", "question": "In a person specification, what does marking an attribute as ''D'' indicate?", "options": ["The attribute is desirable but not essential", "The attribute is required by law", "The candidate must demonstrate it at interview", "The attribute disqualifies the candidate"]}'::jsonb, '{"answer": 0, "explain": "The card explains each attribute in a person specification is marked E (essential) or D (desirable)."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:15e91aa5', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Internal vs External Recruitment", "reading": "<p><strong>Internal recruitment</strong> — filling a vacancy with someone who already works in the organisation.</p>\n<p>Internal advertising methods: noticeboard, word of mouth/staff meetings, company (in-house) magazine, the firm''s website, social media used by workers, emails to workers.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Internal Advantages</div>\n<div class=\"pro-item\">Cheaper to advertise internally</div>\n<div class=\"pro-item\">Quicker — no need to give notice externally</div>\n<div class=\"pro-item\">Person already knows the organisation — less induction training needed</div>\n<div class=\"pro-item\">Organisation already knows the candidate — less risk</div>\n<div class=\"pro-item\">Motivates existing workforce — promotion opportunities</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Internal Disadvantages</div>\n<div class=\"con-item\">Existing staff may not bring new ideas</div>\n<div class=\"con-item\">Limited choice of applicants</div>\n<div class=\"con-item\">Other workers may become jealous — conflict</div>\n<div class=\"con-item\">The job vacated by the person promoted still needs to be filled</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>External recruitment</strong> — filling a vacancy with someone from outside the organisation. Used when: starting up, skills gap exists, new ideas needed, more workers needed, or promoting internally would cause conflict.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ External Advantages</div>\n<div class=\"pro-item\">Wider range of skills and experience</div>\n<div class=\"pro-item\">Fresh ideas from outside the business</div>\n<div class=\"pro-item\">More applicants to choose from</div>\n<div class=\"pro-item\">No need to backfill the promoted person''s role</div>\n</div>\n<div>\n<div class=\"col-head\">✗ External Disadvantages</div>\n<div class=\"con-item\">More expensive (advertising, agency fees)</div>\n<div class=\"con-item\">Takes longer to recruit</div>\n<div class=\"con-item\">Induction training needed — higher cost</div>\n<div class=\"con-item\">Greater risk — managers don''t know the candidate well</div>\n</div>\n</div>", "question": "Which of these is a disadvantage of internal recruitment, according to the card?", "options": ["Their old role still needs to be filled by someone", "It takes longer than external recruitment", "It requires more induction training", "It brings a wider range of skills and experience"]}'::jsonb, '{"answer": 0, "explain": "The card lists that the job vacated by the promoted person still needs to be filled as a disadvantage of internal recruitment; the other options actually describe external recruitment or its disadvantages."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:c7881121', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Advertising Media", "reading": "<p>When advertising a job, a business considers: whether to recruit internally or externally; the type of worker required; how many workers are needed; the location; and the budget available.</p>\n<ul>\n<li><strong>Websites (e.g. Indeed, Reed, Monster)</strong> — Used for all types of jobs, local and national. Applicants can search by type, salary and location. Businesses can search posted CVs. Both internal and external.</li>\n<li><strong>Social media</strong> — Increasingly used for many kinds of jobs because of wide reach. Useful for finding graduates and younger applicants. Both internal and external.</li>\n<li><strong>Local newspapers</strong> — Useful when looking for local workers only (hairdressers, carers, retail). Not usually expensive. External.</li>\n<li><strong>National newspapers</strong> — Used when recruiting skilled workers and there may be a shortage locally. More expensive. External.</li>\n<li><strong>Specialist magazines</strong> — e.g. Times Educational Supplement (teachers), The Lancet (doctors). Used to recruit highly skilled workers such as consultants, engineers, scientists. External.</li>\n<li><strong>Job centres</strong> — Government-run; free to use; useful for people without internet access. External.</li>\n<li><strong>Word of mouth</strong> — Business lets existing employees know about a vacancy. Saves advertising cost. Both internal and external.</li>\n<li><strong>Email/noticeboard/company magazine</strong> — Internal methods only.</li>\n</ul>", "question": "According to the card, what are specialist magazines (e.g. Times Educational Supplement) mainly used to recruit?", "options": ["Highly skilled workers like consultants", "Workers for short-term temporary contracts", "Local unskilled retail staff", "Internal staff seeking promotion"]}'::jsonb, '{"answer": 0, "explain": "The card states specialist magazines are used to recruit highly skilled workers such as consultants, engineers and scientists."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:320c18cf', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Methods of Selection", "reading": "<p>Selection is divided into two stages: shortlisting, then the final selection stage.</p>\n<p><strong>Shortlisting methods</strong> (used to draw up a list of candidates to interview):</p>\n<ul>\n<li><strong>Letter of application</strong> — Written by the applicant explaining why they are suitable. Good for showing communication skills, use of punctuation and grammar, and experience. Applicant puts themselves in the best light.</li>\n<li><strong>CV (curriculum vitae)</strong> — Summary of personal details, qualifications, employment history and referees. Shows ability to organise information. Easy to see essential details at a glance.</li>\n<li><strong>Application form</strong> — Business specifies what information it needs; all applicants fill in the same form. Easy to compare applicants. Less likely to miss essential information than a CV.</li>\n</ul>\n<p><strong>Final selection methods:</strong></p>\n<ul>\n<li><strong>Interviews</strong> — Employer sees candidates face-to-face and can judge how well they present themselves, communicate and are likely to fit in. Often the same questions are asked of all candidates. Good for assessing personality, communication skills and reaction under pressure.</li>\n<li><strong>Tests and presentations</strong> — Check specific skills (e.g. typing, IT, maths). Presentations show how well a candidate can communicate ideas. Gives very specific, measurable information.</li>\n<li><strong>Group activities</strong> — Applicants work together on a task. Reveals interpersonal/teamworking skills and leadership ability. Particularly useful when the job requires working closely with others.</li>\n<li><strong>References</strong> — Statement from a previous employer about work done, how well they did their job, punctuality and attendance. Can verify information from the CV/application form. Provides a third-party view, though references can sometimes be misleading.</li>\n</ul>", "question": "Which method is used at the shortlisting stage rather than the final selection stage?", "options": ["Application form", "Group activity", "Interview", "Reference"]}'::jsonb, '{"answer": 0, "explain": "The card places letters of application, CVs and application forms at the shortlisting stage, while interviews, tests, group activities and references belong to final selection."}'::jsonb),
('business:3-4-recruitment-and-selection:learn:8f92a014', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'learn', 'mcq', 1, '{"readingTitle": "Recruitment & Employment Agencies", "reading": "<p><strong>Recruitment agencies</strong> do the work of recruiting and selecting staff on behalf of businesses. The agency:</p>\n<ul>\n<li>Draws up a job description and person specification (in consultation with the firm)</li>\n<li>Advertises for applications</li>\n<li>Recommends a shortlist of suitable people</li>\n<li>The firm then interviews recommended candidates before making a final decision</li>\n</ul>\n<p>Using a recruitment agency saves time and money if it reduces the need for a large HR department. The agency is a specialist organisation that knows how and where to advertise and what information is needed about applicants.</p>\n<p><strong>Employment agencies</strong> keep lists of people willing to do certain kinds of work (e.g. receptionists, office typists). A firm can ask for a worker for a short period of time, paying the worker''s wage plus the agency''s fee. If the temporary worker performs well, the firm may offer a permanent post — though the agency may charge a further introduction fee.</p>", "question": "What is the key difference between a recruitment agency and an employment agency, according to the card?", "options": ["Employment agencies supply short-term hires; recruitment agencies handle full recruitment", "Recruitment agencies only advertise vacancies, while employment agencies conduct interviews", "Employment agencies are free to use, while recruitment agencies always charge a fee", "Recruitment agencies are used only by small businesses"]}'::jsonb, '{"answer": 0, "explain": "The card explains recruitment agencies carry out the recruitment/selection process for a business, while employment agencies keep lists of workers available for short-term hire."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:78ff8c80', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Recruitment'' and ''selection'' mean the same thing.</p><p><strong>✅ The correct idea:</strong> They are different stages. Recruitment refers to searching for suitable candidates and attracting them to apply for a vacancy. Selection refers to the process of vetting candidates to choose the most suitable person for the role.</p>", "question": "What is the correct distinction between ''recruitment'' and ''selection''?", "options": ["Recruitment attracts candidates; selection vets the best one", "Recruitment and selection are two words for the same process", "Recruitment happens after selection is complete", "Selection means advertising a vacancy"]}'::jsonb, '{"answer": 0, "explain": "The card clarifies recruitment and selection are different stages: recruitment attracts candidates, selection vets them to choose the best person."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:eb3bf49e', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A job description lists the qualifications and skills needed for the job.</p><p><strong>✅ The correct idea:</strong> A job description lists the tasks, duties and responsibilities of the role. Qualifications and skills needed belong in the person specification. Confusing these two documents is one of the most common errors in GCSE exams.</p>", "question": "What does a job description actually list?", "options": ["The tasks, duties and responsibilities of the role", "The qualifications and skills needed for the job", "The salary and benefits package", "The personal qualities of an ideal candidate"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the common misconception that a job description lists qualifications/skills — that belongs in the person specification; a job description lists tasks, duties and responsibilities."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:e9c01ac2', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Internal recruitment is always better because it is cheaper.</p><p><strong>✅ The correct idea:</strong> Internal recruitment has advantages (cheaper, quicker, motivated staff) but also disadvantages (no fresh ideas, limited choice, causes conflict). The best method depends on the specific situation — for example, if a business needs a skills gap filled, external recruitment is needed.</p>", "question": "Why is it wrong to say internal recruitment is ''always better'' than external recruitment?", "options": ["The best method depends on the situation faced", "Because internal recruitment is always more expensive", "Because internal recruitment always causes conflict among staff", "Because external recruitment is always quicker"]}'::jsonb, '{"answer": 0, "explain": "The card explains internal recruitment has both advantages and disadvantages, and the best method depends on the situation — e.g. filling a skills gap needs external recruitment."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:71b17005', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When an employee leaves, a business must always recruit a replacement.</p><p><strong>✅ The correct idea:</strong> Not necessarily. Sometimes the work can be redistributed to other employees. Businesses should analyse their HR needs before automatically recruiting. Recruitment is expensive and time-consuming, so the need must be justified.</p>", "question": "Is it true that a business must always recruit a replacement when an employee leaves?", "options": ["No — the work can sometimes go to other employees", "Yes — a business must recruit within one week by law", "Yes — otherwise the person specification becomes invalid", "No — the role is simply removed from the organisation permanently"]}'::jsonb, '{"answer": 0, "explain": "The card corrects this misconception, explaining that work can sometimes be redistributed to other employees, and the need to recruit must be justified since it is expensive and time-consuming."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:2c74f014', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A CV is better than an application form because the applicant includes all the information.</p><p><strong>✅ The correct idea:</strong> A CV shows the applicant''s ability to organise information, but applicants may leave out essential details. Application forms ensure all applicants provide exactly the same information, making it easier to compare them. Each method has its advantages.</p>", "question": "Why might an application form be considered better than a CV for comparing applicants?", "options": ["It ensures every applicant gives the same information", "It always includes more personal details than a CV", "It is cheaper to produce than a CV", "It guarantees the applicant is telling the truth"]}'::jsonb, '{"answer": 0, "explain": "The card explains application forms ensure all applicants provide identical information, making comparison easier, whereas a CV''s structure is decided by the applicant and may omit details."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:002555ca', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> References always provide accurate, honest information about a candidate.</p><p><strong>✅ The correct idea:</strong> References can be misleading. Sometimes employers give workers good references because they want them to leave. For this reason, businesses often use more than one method of selection to build a fuller picture of each candidate.</p>", "question": "Why can references sometimes be misleading?", "options": ["Employers may give good references to workers they want gone", "References are only used for internal recruitment", "References are always written by the candidate themselves", "References replace the need for an interview"]}'::jsonb, '{"answer": 0, "explain": "The card notes that employers sometimes give good references because they want a worker to leave, which is why businesses use more than one selection method."}'::jsonb),
('business:3-4-recruitment-and-selection:misc:dc5f8eb5', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Some learners refer to the ''person specification'' as the ''job specification''.</p><p><strong>✅ The correct idea:</strong> The correct term used in the OCR specification is ''person specification''. Always use this term in your answers to show precise subject knowledge.</p>", "question": "Which term is the correct OCR specification term for the document listing a candidate''s required qualities and qualifications?", "options": ["Person specification", "Job specification", "Candidate description", "Role specification"]}'::jsonb, '{"answer": 0, "explain": "The card states the correct OCR term is ''person specification'', not ''job specification''."}'::jsonb),
('business:3-4-recruitment-and-selection:tips:d67b20f6', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tips', 'mcq', 1, '{"readingTitle": "Question Type — 2-mark Explain questions (AO1b + AO2)", "reading": "<p>You need <strong>Knowledge (1 mark)</strong> + <strong>Application (1 mark)</strong>.</p>\n<p>State the advantage/disadvantage, then link it specifically to the business in the question.</p>\n<p><em>Example: \"External recruitment may bring new ideas (K) which is important for Waitrose as it operates in a very competitive supermarket industry where new product development is key (APP).\"</em></p>", "question": "What two marks make up a 2-mark ''Explain'' question (AO1b + AO2)?", "options": ["Knowledge (1 mark) + Application (1 mark)", "Knowledge (1 mark) + Evaluation (1 mark)", "Application (1 mark) + Analysis (1 mark)", "Understanding (1 mark) + Evaluation (1 mark)"]}'::jsonb, '{"answer": 0, "explain": "The card states 2-mark Explain questions require Knowledge (1 mark) plus Application (1 mark), linking the point specifically to the business in the question."}'::jsonb),
('business:3-4-recruitment-and-selection:tips:9a65affe', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tips', 'mcq', 1, '{"readingTitle": "Question Type — 3-mark Analyse questions (AO1b + AO2 + AO3a)", "reading": "<p>State the advantage/method → Apply to the business → Analyse the business impact.</p>\n<p><em>Example: \"Interviews allow the interviewer to ask detailed questions about the candidates'' skills (K). Given that Clarks designers work with fast-changing fashion trends (APP), this will allow Clarks to select workers who are up-to-date, potentially increasing market share (AN).\"</em></p>", "question": "What is the correct structure for a 3-mark ''Analyse'' question?", "options": ["State the method, apply it, then analyse the impact", "State the advantage, then make a final judgement", "Describe the method, then compare it to an alternative", "State two separate advantages of the method"]}'::jsonb, '{"answer": 0, "explain": "The card explains 3-mark Analyse questions require: state the advantage/method, apply it to the business, then analyse the business impact (K+APP+AN)."}'::jsonb),
('business:3-4-recruitment-and-selection:tips:8636ca01', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tips', 'mcq', 1, '{"readingTitle": "Question Type — 3-mark Recommend questions (AO3b)", "reading": "<p>You must: (1) Make a clear decision — don''t sit on the fence. (2) Justify why your chosen method is better than the alternative — a comparison is essential. (3) Use context from the case study.</p>\n<p><em>Example: \"Interviews are likely to be more effective (1) because Clarks can assess candidates'' knowledge of current fashion (CONT). A reference is unlikely to include this information unless they previously worked for another fashion business (+2).\"</em></p>", "question": "What must a student do to access full marks on a 3-mark ''Recommend'' question (AO3b)?", "options": ["Make a decision, justified against the alternative", "List as many advantages as possible without choosing one option", "Describe both methods without making a decision", "Simply repeat the question in the answer"]}'::jsonb, '{"answer": 0, "explain": "The card states students must make a clear decision, justify why the chosen method is better than the alternative (a comparison is essential), and use case study context."}'::jsonb),
('business:3-4-recruitment-and-selection:tips:3af74f32', 'business', 'business:3-4-recruitment-and-selection', '3.4 Recruitment and Selection', 'tips', 'mcq', 1, '{"readingTitle": "Question Type — 9-mark Evaluate questions (AO1a + AO1b + AO2 + AO3a + AO3b)", "reading": "<p>Use the marking grid: Knowledge (1) → Understanding (1) → Application/data (2) → Analysis (2) → Evaluation (3).</p>\n<ul>\n<li>Use data from the case study to earn application marks (e.g. calculate differences in costs)</li>\n<li>Give both advantages and disadvantages of the recruitment method</li>\n<li>Make a final judgement that is contextually justified using information from the case study</li>\n</ul>", "question": "According to the marking grid for a 9-mark Evaluate question, how many marks are allocated to Evaluation?", "options": ["3 marks", "1 mark", "2 marks", "4 marks"]}'::jsonb, '{"answer": 0, "explain": "The card''s marking grid allocates Knowledge (1) + Understanding (1) + Application/data (2) + Analysis (2) + Evaluation (3) = 9 marks."}'::jsonb)
